import json
import boto3
from botocore.exceptions import ClientError

def lambda_handler(event, context):
    # Get the message content and topic ARN from the event data
    message = event['message']
    topic_arn = event['topic_arn']
    
    # Validate the input to prevent malicious or unexpected values
    if not isinstance(message, str) or len(message) > 256:
        raise ValueError("Invalid message content")
    if not isinstance(topic_arn, str) or len(topic_arn) > 1024:
        raise ValueError("Invalid topic ARN")
    
    # Use secure platform APIs to publish the message to SNS
    sns = boto3.client('sns')
    try:
        response = sns.publish(TopicArn=topic_arn, Message=message)
    except ClientError as e:
        raise ValueError("Failed to publish message to SNS") from e
    
    # Return the response from SNS
    return response